+ (void)logReferralActivitywithCode:(NSString *)code {
    //    [WBEventManager addEventWithType:eventTypeReferralClick code:code urgent:false];
    WBEventManager *manager = [WBEventManager defaultManager];
    dispatch_async(manager.queue, ^{
        // 获取或创建该事件类型的计数字典
        NSNumber *eventTypeKey = @(eventTypeReferralClick);
        NSMutableDictionary *codeCounts = manager.mergeableEventCounts[eventTypeKey];
        if (!codeCounts) {
            codeCounts = [[NSMutableDictionary alloc] init];
            manager.mergeableEventCounts[eventTypeKey] = codeCounts;
        }

        // 累加计数
        NSNumber *currentCount = codeCounts[code];
        NSInteger count = currentCount ? [currentCount integerValue] : 0;
        codeCounts[code] = @(count + 1);
    });
}

