- (void)handleConfirm {
    [self.view endEditing:YES];

    if (!WBReferralManager.sharedManager.activityStart) {
        [SVProgressHUD showInfoWithStatus:@"活动未开启"];
        return;
    }

    // 防空：检查输入是否为空
    NSString *code = [self.codeTextfield.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if (code.length == 0) {
        [SVProgressHUD showErrorWithStatus:NSLocalizedString(@"请输入邀请码", nil)];
        return;
    }

    // 防抖：防止重复提交
    if (self.isSubmitting) {
        NSLog(@"beidangzhule");
        return;
    }

    self.isSubmitting = YES;
    [SVProgressHUD show];

    [[WBNetworkManager defaultManager] sendReferralCode:@([code longLongValue])  callback:^(id  _Nullable json, NSError * _Nullable error) {
        self.isSubmitting = NO;
        [SVProgressHUD dismiss];

        if (error) {
            NSString *descriptionStr =  error.userInfo[@"NSLocalizedDescription"];
            [SVProgressHUD showErrorWithStatus:descriptionStr];
        } else {
            // 刷新邀请数据
            [[WBReferralManager sharedManager] refreshReferralData];
